// // This module implements a D flip-flop with clock gating. The output Q is updated on every rising edge of the clock regardless of the state of the clock enable signal CE.
module gated_dff (
    input wire clk,
    input wire D,
    input wire CE,
    output reg Q
);
    always @(posedge clk) begin
        if (CE) begin
            Q <= D;
        end
    end
endmodule
